module RefModule(
    input clk,
    input rst,
    input en,
    output [3:0] count
);reg [3:0] obf_count_reg;

    always @(posedge clk) begin
        if (rst) begin
            obf_count_reg <= 4'b0;
        end else if (en) begin
            obf_count_reg <= obf_count_reg + 1;
        end
    end

    assign count = obf_count_reg;

endmodule
